typedef enum SDL_DateFormat
{
 SDL_DATE_FORMAT_YYYYMMDD = 0, /**< تشير هذه القيمة إلى أن SDL ترتب مكونات التاريخ بصيغة سنة/شهر/يوم عند عرض التاريخ أو تفسيره في هذا السياق. */
 SDL_DATE_FORMAT_DDMMYYYY = 1, /**< تشير هذه القيمة إلى أن SDL ترتب مكونات التاريخ بصيغة يوم/شهر/سنة عند عرض التاريخ أو تفسيره في هذا السياق. */
 SDL_DATE_FORMAT_MMDDYYYY = 2 /**< تشير هذه القيمة إلى أن SDL ترتب مكونات التاريخ بصيغة شهر/يوم/سنة عند عرض التاريخ أو تفسيره في هذا السياق. */
} SDL_DateFormat;
